import{_ as e,a as t,b as n,c as i,d as o}from"./chunks/复制刷新令牌.IwW3dosg.js";import{_ as r,o as d,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Tambah OneDrive Channel","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/upload/onedrive.md","filePath":"ms-MY/upload/onedrive.md","lastUpdated":1781962217000}'),p={name:"ms-MY/upload/onedrive.md"};function c(h,a,u,m,k,b){return d(),s("div",null,[...a[0]||(a[0]=[l('<h1 id="tambah-onedrive-channel" tabindex="-1">Tambah OneDrive Channel <a class="header-anchor" href="#tambah-onedrive-channel" aria-label="Permalink to &quot;Tambah OneDrive Channel&quot;">​</a></h1><h2 id="perkara-yang-perlu-disediakan-dahulu" tabindex="-1">Perkara Yang Perlu Disediakan Dahulu <a class="header-anchor" href="#perkara-yang-perlu-disediakan-dahulu" aria-label="Permalink to &quot;Perkara Yang Perlu Disediakan Dahulu&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Mengapa Diperlukan</th></tr></thead><tbody><tr><td>Microsoft account</td><td>Digunakan untuk mengakses Microsoft admin pages dan authorize OneDrive</td></tr><tr><td>ImgBed domain anda</td><td>Digunakan untuk OAuth callback URL</td></tr><tr><td>App registration</td><td>Digunakan untuk generate <code>Client ID</code> dan <code>Client Secret</code></td></tr><tr><td>OneDrive account</td><td>Digunakan sebagai lokasi storage sebenar</td></tr></tbody></table><h2 id="langkah-setup" tabindex="-1">Langkah Setup <a class="header-anchor" href="#langkah-setup" aria-label="Permalink to &quot;Langkah Setup&quot;">​</a></h2><h3 id="step-1-buka-microsoft-entra-id" tabindex="-1">Step 1: Buka Microsoft Entra ID <a class="header-anchor" href="#step-1-buka-microsoft-entra-id" aria-label="Permalink to &quot;Step 1: Buka Microsoft Entra ID&quot;">​</a></h3><ol><li>Buka <code>portal.azure.com</code>.</li><li>Cari <code>Microsoft Entra ID</code> di bahagian atas.</li><li>Jika halaman sasaran tidak muncul dalam dropdown, pilih:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Continue searching in Microsoft Entra ID</span></span></code></pre></div><ol start="4"><li>Buka <code>Microsoft Entra ID</code>.</li><li>Buka <code>App registrations</code>.</li><li>Klik <code>New registration</code>.</li></ol><h3 id="step-2-register-app" tabindex="-1">Step 2: Register App <a class="header-anchor" href="#step-2-register-app" aria-label="Permalink to &quot;Step 2: Register App&quot;">​</a></h3><p>Pada halaman <code>New registration</code>, isi:</p><table tabindex="0"><thead><tr><th>Field</th><th>Apa Yang Perlu Diisi</th></tr></thead><tbody><tr><td>Name</td><td>Nama yang mudah dikenali, contohnya <code>imgbed-onedrive</code></td></tr><tr><td>Supported account types</td><td>Pilih berdasarkan jadual di bawah</td></tr><tr><td>Redirect URI type</td><td><code>Web</code></td></tr><tr><td>Redirect URI</td><td><code>https://your-domain.com/api/oauth/onedrive/callback</code></td></tr></tbody></table><p>Panduan account type:</p><table tabindex="0"><thead><tr><th>Situasi Anda</th><th>Supported Account Types</th></tr></thead><tbody><tr><td>Personal OneDrive sahaja</td><td>Pilih pilihan personal Microsoft account.</td></tr><tr><td>Personal dan work/school accounts</td><td>Pilih pilihan yang menyokong kedua-dua personal dan organizational accounts.</td></tr><tr><td>Company atau school OneDrive sahaja</td><td>Pilih organizational account option.</td></tr></tbody></table><p>Klik register selepas borang lengkap.</p><p><img src="'+e+'" alt="Create OneDrive app" loading="lazy"></p><h3 id="step-3-copy-app-information" tabindex="-1">Step 3: Copy App Information <a class="header-anchor" href="#step-3-copy-app-information" aria-label="Permalink to &quot;Step 3: Copy App Information&quot;">​</a></h3><p>Selepas app dicipta, copy nilai ini dari overview page:</p><table tabindex="0"><thead><tr><th>Microsoft Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>Application (client) ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Directory (tenant) ID</code></td><td><code>Tenant ID</code> untuk organizational accounts</td></tr></tbody></table><p><img src="'+t+'" alt="Application and tenant IDs" loading="lazy"></p><h3 id="step-4-cipta-client-secret" tabindex="-1">Step 4: Cipta Client Secret <a class="header-anchor" href="#step-4-cipta-client-secret" aria-label="Permalink to &quot;Step 4: Cipta Client Secret&quot;">​</a></h3><ol><li>Buka <code>Certificates &amp; secrets</code>.</li><li>Klik <code>New client secret</code>.</li><li>Masukkan description yang anda mahu.</li><li>Pilih expiration period.</li><li>Copy <code>Value</code> sebaik sahaja ia dicipta.</li></ol><p><img src="'+n+'" alt="Save client secret value" loading="lazy"></p><h3 id="step-5-tambah-api-permissions" tabindex="-1">Step 5: Tambah API Permissions <a class="header-anchor" href="#step-5-tambah-api-permissions" aria-label="Permalink to &quot;Step 5: Tambah API Permissions&quot;">​</a></h3><ol><li>Buka <code>API permissions</code>.</li><li>Klik <code>Add a permission</code>.</li><li>Pilih <code>Microsoft Graph</code>.</li><li>Pilih <code>Delegated permissions</code>.</li><li>Tambah permissions ini:</li></ol><table tabindex="0"><thead><tr><th>Permission</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Files.ReadWrite.All</code></td><td>Upload files, cipta folders dan delete files</td></tr><tr><td><code>offline_access</code></td><td>Membolehkan ImgBed mendapatkan <code>Refresh Token</code></td></tr><tr><td><code>User.Read</code></td><td>Membaca account dan quota information</td></tr></tbody></table><h3 id="step-6-isi-onedrive-channel" tabindex="-1">Step 6: Isi OneDrive Channel <a class="header-anchor" href="#step-6-isi-onedrive-channel" aria-label="Permalink to &quot;Step 6: Isi OneDrive Channel&quot;">​</a></h3><p>Dalam Upload Settings, pilih <code>OneDrive</code> dan isi:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>Apa Yang Perlu Diisi</th></tr></thead><tbody><tr><td>Channel name</td><td>Nama mudah dikenali, contohnya <code>Main OneDrive</code></td></tr><tr><td>Client ID</td><td>Microsoft <code>Application (client) ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret Value</code> yang anda copy</td></tr><tr><td>Tenant ID</td><td>Gunakan jadual di bawah</td></tr><tr><td>Refresh Token</td><td>Biarkan kosong buat masa ini</td></tr><tr><td>Root directory</td><td>Optional. Default ialah <code>imgbed</code>.</td></tr><tr><td>Note</td><td>Optional</td></tr></tbody></table><p><img src="'+i+'" alt="Fill OneDrive channel config" loading="lazy"></p><p>Cara mengisi <code>Tenant ID</code>:</p><table tabindex="0"><thead><tr><th>Account Type You Chose</th><th>ImgBed <code>Tenant ID</code></th></tr></thead><tbody><tr><td>Personal accounts</td><td><code>consumers</code></td></tr><tr><td>Personal + organizational accounts</td><td><code>common</code></td></tr><tr><td>Current organization only</td><td><code>Directory (tenant) ID</code></td></tr></tbody></table><h3 id="step-7-dapatkan-refresh-token" tabindex="-1">Step 7: Dapatkan Refresh Token <a class="header-anchor" href="#step-7-dapatkan-refresh-token" aria-label="Permalink to &quot;Step 7: Dapatkan Refresh Token&quot;">​</a></h3><ol><li>Dalam ImgBed, klik <code>Get Token</code>.</li><li>Sign in ke Microsoft account yang mahu disambungkan.</li><li>Approve authorization prompt.</li><li>Callback page akan menunjukkan <code>Refresh Token</code>.</li><li>Copy token tersebut.</li><li>Kembali ke ImgBed dan paste dalam field <code>Refresh Token</code>.</li></ol><p><img src="'+o+`" alt="Copy refresh token" loading="lazy"></p><h3 id="step-8-save-channel" tabindex="-1">Step 8: Save Channel <a class="header-anchor" href="#step-8-save-channel" aria-label="Permalink to &quot;Step 8: Save Channel&quot;">​</a></h3><p>Selepas semua field diisi, save channel.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Buka portal.azure.com</span></span>
<span class="line"><span>-&gt; Cari Microsoft Entra ID</span></span>
<span class="line"><span>-&gt; Buka App registrations</span></span>
<span class="line"><span>-&gt; Register app baharu</span></span>
<span class="line"><span>-&gt; Isi Name / Supported account types / Web redirect URI</span></span>
<span class="line"><span>-&gt; Register</span></span>
<span class="line"><span>-&gt; Copy Application (client) ID</span></span>
<span class="line"><span>-&gt; Semak callback URL dalam Authentication</span></span>
<span class="line"><span>-&gt; Cipta Client Secret dalam Certificates &amp; secrets</span></span>
<span class="line"><span>-&gt; Tambah permissions dalam API permissions</span></span>
<span class="line"><span>-&gt; Isi Client ID / Client Secret / Tenant ID dalam ImgBed</span></span>
<span class="line"><span>-&gt; Klik Get Token</span></span>
<span class="line"><span>-&gt; Copy Refresh Token dari callback page</span></span>
<span class="line"><span>-&gt; Paste kembali ke ImgBed dan save</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Microsoft Entra app registration: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app</a></li><li>Microsoft identity platform authorization code flow: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow</a></li><li>Microsoft Graph user authentication: <a href="https://learn.microsoft.com/en-us/graph/auth-v2-user" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/graph/auth-v2-user</a></li></ol>`,40)])])}const D=r(p,[["render",c]]);export{y as __pageData,D as default};
